    def test_imperial_sinkware_parser_keeps_single_word_undermount_and_supplier(self) -> None:
        text = (
            "SINKWARE & TAPWARE\n"
            "AREA / ITEM SPECS / DESCRIPTION IMAGE SUPPLIER NOTES\n"
            "Burazzo 650mm Stainless Steel Single Bowl\n"
            "Taphole location: In Stone, centered behind\n"
            "SINK (PANTRY) Sink (BU654520S)- Sink Mounting - By Others\n"
            "sink\n"
            "Undermount\n"
            "Stella Inset Stainless Steel 45 Litre\n"
            "SINK (LAUNDRY) By Others Taphole location: In Sink corner LHS\n"
            "(YH236C) - Sink Mounting - Topmount -\n"
        )
        blocks = dict(parsing_module._imperial_extract_non_joinery_blocks(text, "sinkware"))
        self.assertIn("PANTRY", blocks)
        self.assertIn("By Others", blocks["PANTRY"])
        self.assertIn("Undermount", blocks["PANTRY"])
        self.assertIn("Taphole location: In Stone, centered behind sink", blocks["PANTRY"])

    def test_imperial_fixture_overlay_prefers_complete_supplier_and_mounting_candidate(self) -> None:
        existing = (
            "Burazzo 650mm Stainless Steel Single Bowl Sink (BU654520S)- "
            "Sink Mounting - Taphole location: In Stone, centered behind sink"
        )
        candidate = (
            "Burazzo 650mm Stainless Steel Single Bowl Sink (BU654520S)- "
            "Sink Mounting - By Others - Taphole location: In Stone, centered behind sink - Undermounted"
        )
        self.assertEqual(
            parsing_module._imperial_prefer_fixture_overlay_text(existing, candidate, "sink"),
            candidate,
        )

    def test_clean_room_fixture_text_repairs_imperial_sinkware_taphole_tails(self) -> None:
        self.assertEqual(
            parsing_module._clean_room_fixture_text(
                "Burazzo 650mm Stainless Steel Single Bowl Sink (BU654520S)- "
                "Sink Mounting Undermount sink - Taphole location: In Stone, centered behind",
                "sink",
            ),
            "Burazzo 650mm Stainless Steel Single Bowl Sink (BU654520S)- "
            "Sink Mounting - Undermount - By Others - Taphole location: In Stone, centered behind sink",
        )
        self.assertEqual(
            parsing_module._clean_room_fixture_text(
                "Sink Mounting - Topmount - Specs TBC By Others - Taphole location: In Stone, centered behind basin sink",
                "basin",
            ),
            "Sink Mounting - Topmount - Specs TBC - By Others - Taphole location: In Stone, centered behind basin",
        )
        self.assertEqual(
            parsing_module._clean_room_fixture_text(
                "Sink Mounting - Topmount - Specs TBC By Others - Taphole location: In Stone, centered behind",
                "basin",
            ),
            "Sink Mounting - Topmount - Specs TBC - By Others - Taphole location: In Stone, centered behind basin",
        )
        self.assertEqual(
            parsing_module._clean_room_fixture_text(
                "Stella Inset Stainless Steel 45 Litre (YH236C)- Sink Moun\u019fng - Topmount - By Others",
                "sink",
            ),
            "Stella Inset Stainless Steel 45 Litre (YH236C)- Sink Mounting - Topmount - By Others",
        )
        self.assertEqual(
            parsing_module._clean_room_fixture_text(
                "Memo Hugo Single bowl sink 425W x 445H x 220D - Sink Mounting - TBC By Others - Taphole location: TBC",
                "sink",
            ),
            "Memo Hugo Single bowl sink 425W x 445H x 220D - Sink Mounting - TBC - By Others - Taphole location: TBC",
        )
        self.assertEqual(
            parsing_module._clean_room_fixture_text(
                "Bench top is to remain Existing Sink and Tap to be used - Sink Mounting - TBC - Taphole location: No hole cut out required",
                "sink",
            ),
            "Bench top is to remain Existing Sink and Tap to be used - Sink Mounting - TBC - By Others - Taphole location: No hole cut out required",
        )

    def test_imperial_assign_sinkware_cluster_parts_keeps_room_specific_lines_local(self) -> None:
        assigned = parsing_module._imperial_assign_sinkware_cluster_parts(
            [
                ("KITCHEN", "Existing Sink and Tap to be used"),
                ("LAUNDRY", "Memo Hugo Single bowl sink 425W x 445H x 220D"),
            ],
            [],
            [
                "KITCHEN Taphole location: No hole cut out required",
                "LAUNDRY Mizu Drift sink mixer - Matte Black",
            ],
        )
        self.assertEqual(
            assigned,
            [
                [
                    "Existing Sink and Tap to be used",
                    "KITCHEN Taphole location: No hole cut out required",
                ],
                [
                    "Memo Hugo Single bowl sink 425W x 445H x 220D",
                    "LAUNDRY Mizu Drift sink mixer - Matte Black",
                ],
            ],
        )

