        self.assertEqual(
            rooms_by_key["laundry"]["material_rows"][3]["specs_or_description"],
            "Polytec - Boston Oak - Woodmatt",
        )
        self.assertEqual(
            rooms_by_key["storage_nook"]["material_rows"][-1]["specs_or_description"],
            "Allegra - 3750 192 MB OA = 202mm - Horizontally - DRAWER",
        )

