    def test_imperial_separator_model_to_dict_keeps_segment_source_and_confidence(self) -> None:
        model = extraction_service.ImperialSeparatorModel(
            visible_horizontal_segments=[
                {
                    "orientation": "horizontal",
                    "edge": 120.0,
                    "start": 32.0,
                    "end": 540.0,
                    "source": "visible_line",
                    "confidence": "visible",
                }
            ],
            inferred_horizontal_segments=[
                {
                    "orientation": "horizontal",
                    "edge": 240.0,
                    "start": 32.0,
                    "end": 540.0,
                    "source": "bridge_over_image",
                    "confidence": "inferred_high",
                }
            ],
        )
        payload = model.to_dict()
        self.assertEqual(payload["visible_horizontal_segments"][0]["source"], "visible_line")
        self.assertEqual(payload["visible_horizontal_segments"][0]["confidence"], "visible")
        self.assertEqual(payload["inferred_horizontal_segments"][0]["source"], "bridge_over_image")
        self.assertEqual(payload["inferred_horizontal_segments"][0]["confidence"], "inferred_high")

    def test_imperial_grid_merge_rejects_header_polluted_layout_candidate(self) -> None:
        cell_row = extraction_service.ImperialGridRow(
            room_scope="KITCHEN & PANTRY",
            row_label="BENCHTOP",
            description="40mm Stone | WFE x 1",
            supplier="By Others",
            row_kind="material",
            row_order=1,
            repair_source="cell_grid_repair",
            confidence=0.72,
        )
        polluted_candidate = extraction_service.ImperialGridRow(
            room_scope="KITCHEN & PANTRY",
            row_label="BENCHTOP",
            description=(
                "Bulkhead:Colourboard IMAGE Yes 40mm Stone Cabinetry Height:2400mm "
                "KITCHEN & PANTRY JOINERY SELECTION SHEET Address: Lot 1041 Rufous Street"
            ),
            supplier="By Others",
            row_kind="material",
            row_order=1,
            repair_source="vision_table_repair",
            confidence=0.98,
        )
        preferred = extraction_service._prefer_imperial_grid_row(cell_row, polluted_candidate)
        self.assertEqual(preferred.description, "40mm Stone | WFE x 1")
        self.assertNotIn("Bulkhead", preferred.description)

    def test_imperial_word_bboxes_flow_to_cell_ownership_provenance(self) -> None:
        page_words = (
            (10.0, 10.0, 95.0, 20.0, "AREA / ITEM"),
            (10.0, 200.0, 345.0, 20.0, "SPECS / DESCRIPTION"),
            (10.0, 800.0, 860.0, 20.0, "SUPPLIER"),
            (10.0, 940.0, 990.0, 20.0, "NOTES"),
            (30.0, 10.0, 80.0, 40.0, "BENCHTOP"),
            (30.0, 200.0, 285.0, 40.0, "40mm Stone"),
            (30.0, 800.0, 870.0, 40.0, "By Others"),
            (30.0, 940.0, 990.0, 40.0, "WFE x 1"),
        )
        rows, unresolved = extraction_service._extract_imperial_joinery_word_grid_rows(
            page_words,
            room_scope="KITCHEN & PANTRY",
            page_no=1,
            separator_model=extraction_service.ImperialSeparatorModel(),
        )
        self.assertEqual(unresolved, [])
        self.assertEqual(len(rows), 1)
        provenance = rows[0].provenance or {}
        self.assertEqual(provenance["page_structure"]["content_grid_bbox"]["top"], 30.0)
        self.assertEqual(provenance["area_or_item"]["x1"], 80.0)
        self.assertEqual(provenance["area_or_item"]["bottom"], 40.0)
        ownership = provenance["cell_ownership"]
        self.assertTrue(any(cell["role"] == "supplier" and cell["text"] == "By Others" for cell in ownership))

